CA;AACA;AACA;AACA;AACA;AACA;AACA,uCAAuC,WAAW;AAClD,kCAAkC,6BAA6B;AAC/D;AACA;AACA;AACA,kCAAkC,6BAA6B;AAC/D;AACA;AACA;AACA,kCAAkC,6BAA6B;AAC/D;AACA;AACA;AACA;AACA;AACA;AACA;AACA,qBAAqB;AACrB;AACA;AACA,gCAAgC,6BAA6B;AAC7D;AACA;AACA;AACA,gCAAgC,6BAA6B;AAC7D;AACA;AACA;AACA;AACA;AACA;AACA,iCAAiC;AACjC;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA,qBAAqB,6BAA6B;AAClD,kBAAkB,sBAAsB;AACxC;AACA;AACA;AACA;AACA,kBAAkB;AAClB,IAAI,KAAU;AACd;AACA;AACA;AACA;AACA,C","file":"194.js","sourcesContent":["var disposed = false\nvar normalizeComponent = require(\"!../../../../../../node_modules/vue-loader/lib/component-normalizer\")\n/* script */\nvar __vue_script__ = require(\"!!babel-loader?{\\\"cacheDirectory\\\":true,\\\"presets\\\":[[\\\"@babel/preset-env\\\",{\\\"modules\\\":false,\\\"targets\\\":{\\\"browsers\\\":[\\\"> 2%\\\"]},\\\"forceAllTransforms\\\":true}]],\\\"plugins\\\":[\\\"@babel/plugin-proposal-object-rest-spread\\\",[\\\"@babel/plugin-transform-runtime\\\",{\\\"helpers\\\":false}]]}!../../../../../../node_modules/vue-loader/lib/selector?type=script&index=0!./service_form.vue\")\n/* template */\nvar __vue_template__ = require(\"!!../../../../../../node_modules/vue-loader/lib/template-compiler/index?{\\\"id\\\":\\\"data-v-3fbe7136\\\",\\\"hasScoped\\\":false,\\\"buble\\\":{\\\"transforms\\\":{}}}!../../../../../../node_modules/vue-loader/lib/selector?type=template&index=0!./service_form.vue\")\n/* template functional */\nvar __vue_template_functional__ = false\n/* styles */\nvar __vue_styles__ = null\n/* scopeId */\nvar __vue_scopeId__ = null\n/* moduleIdentifier (server only) */\nvar __vue_module_identifier__ = null\nvar Component = normalizeComponent(\n  __vue_script__,\n  __vue_template__,\n  __vue_template_functional__,\n  __vue_styles__,\n  __vue_scopeId__,\n  __vue_module_identifier__\n)\nComponent.options.__file = \"modules/College/Resources/assets/js/components/service_form.vue\"\n\n/* hot reload */\nif (module.hot) {(function () {\n  var hotAPI = require(\"vue-hot-reload-api\")\n  hotAPI.install(require(\"vue\"), false)\n  if (!hotAPI.compatible) return\n  module.hot.accept()\n  if (!module.hot.data) {\n    hotAPI.createRecord(\"data-v-3fbe7136\", Component.options)\n  } else {\n    hotAPI.reload(\"data-v-3fbe7136\", Component.options)\n  }\n  module.hot.dispose(function (data) {\n    disposed = true\n  })\n})()}\n\nmodule.exports = Component.exports\n\n\n\n//////////////////\n// WEBPACK FOOTER\n// ./modules/College/Resources/assets/js/components/service_form.vue\n// module id = ./modules/College/Resources/assets/js/components/service_form.vue\n// module chunks = 194","<template>\r\n    <div class=\"card bg-ligth\" v-loading=\"loading\">\r\n        <div class=\"row mt-2\">\r\n            <div class=\"col-12\">\r\n                <label class=\"label-control w-100\">Plan</label>\r\n                <el-select v-model=\"form.plan_id\" @change=\"changePlan\">\r\n                    <el-option\r\n                        v-for=\"(plan, idx) in plans\"\r\n                        :key=\"idx\"\r\n                        :label=\"\r\n                            `${plan.name} ${plan.description} S/${plan.total}`\r\n                        \"\r\n                        :value=\"plan.id\"\r\n                    >\r\n                    </el-option>\r\n                </el-select>\r\n                <label v-if=\"paymentDay\" class=\"mt-2 label-control\"\r\n                    >Vencimiento:\r\n                    <strong>\r\n                        {{ `${paymentDay.split(\"/\")[0]} de cada mes` }}</strong\r\n                    ></label\r\n                >\r\n                <label\r\n                    v-if=\"currentPlan && currentPlan.days_extension != 0\"\r\n                    class=\"text-primary\"\r\n                    style=\"font-weight:bold\"\r\n                >\r\n                    / Prorroga:\r\n                    <strong> {{ currentPlan.days_extension }} días </strong>\r\n                </label>\r\n            </div>\r\n        </div>\r\n        <div class=\"row mt-1 \">\r\n            <el-checkbox-group\r\n                :disabled=\"!form.plan_id\"\r\n                v-model=\"selectedMonths\"\r\n                class=\" d-flex flex-wrap justify-content-center\"\r\n                @change=\"selectMonth\"\r\n            >\r\n                <el-checkbox-button\r\n                    class=\"mt-1\"\r\n                    v-for=\"m in months\"\r\n                    :disabled=\"m.disabled\"\r\n                    :label=\"m.id\"\r\n                    :key=\"m.id\"\r\n                    >{{ m.label }}</el-checkbox-button\r\n                >\r\n            </el-checkbox-group>\r\n        </div>\r\n        <div\r\n            v-if=\"penalties.length != 0\"\r\n            class=\"row p-2 d-flex justify-content-center\"\r\n        >\r\n            <table class=\"table-sm table-bordered border-danger w-75\">\r\n                <thead class=\"thead-dark\">\r\n                    <tr>\r\n                        <th class=\"text-center\">\r\n                            Mes\r\n                        </th>\r\n                        <th class=\"text-center\">Días de retraso</th>\r\n                        <th class=\"text-center\">\r\n                            Penalidad x día{{\r\n                                currentPlan.penalty.type == \"percentage\"\r\n                                    ? ` ${currentPlan.penalty.percentage} %`\r\n                                    : ` S/ ${currentPlan.penalty.percentage}`\r\n                            }}\r\n                        </th>\r\n                    </tr>\r\n                </thead>\r\n                <tbody>\r\n                    <tr v-for=\"(penal, idx) in penalties\" :key=\"idx\">\r\n                        <td class=\"text-center\">{{ penal.label }}</td>\r\n                        <td class=\"text-center\">{{ penal.days }}</td>\r\n                        <td class=\"text-center\">\r\n                            {{ penal.penalty.toFixed(2) }}\r\n                        </td>\r\n                    </tr>\r\n                    <tr>\r\n                        <td class=\"text-center\"></td>\r\n                        <td class=\"text-center\">\r\n                            <span class=\"bold\">Total</span>\r\n                        </td>\r\n                        <td class=\"text-center\">\r\n                            {{\r\n                                penalties\r\n                                    .reduce((a, b) => a + Number(b.penalty), 0)\r\n                                    .toFixed(2)\r\n                            }}\r\n                        </td>\r\n                    </tr>\r\n                </tbody>\r\n            </table>\r\n        </div>\r\n    </div>\r\n</template>\r\n<script>\r\nimport moment from \"moment\";\r\nexport default {\r\n    props: [\"member\"],\r\n\r\n    data() {\r\n        return {\r\n            resource: \"registers\",\r\n            loading: false,\r\n            plans: [],\r\n            date: moment(),\r\n            monthsPayed: [],\r\n            paymentDay: null,\r\n            form: {},\r\n            currentPlan: null,\r\n            penalties: [],\r\n            limitDate: null,\r\n            selectedMonths: [],\r\n            months: [\r\n                { id: 1, label: \"Enero\", disabled: false },\r\n                { id: 2, label: \"Febrero\", disabled: false },\r\n                { id: 3, label: \"Marzo\", disabled: false },\r\n                { id: 4, label: \"Abril\", disabled: false },\r\n                { id: 5, label: \"Mayo\", disabled: false },\r\n                { id: 6, label: \"Junio\", disabled: false },\r\n                { id: 7, label: \"Julio\", disabled: false },\r\n                { id: 8, label: \"Agosto\", disabled: false },\r\n                { id: 9, label: \"Setiembre\", disabled: false },\r\n                { id: 10, label: \"Octubre\", disabled: false },\r\n                { id: 11, label: \"Noviembre\", disabled: false },\r\n                { id: 12, label: \"Diciembre\", disabled: false }\r\n            ]\r\n        };\r\n    },\r\n    async created() {\r\n        // await this.getTables();\r\n    },\r\n    methods: {\r\n        changePlan() {\r\n            this.paymentDay = null;\r\n            this.penalties = [];\r\n            this.currentPlan = null;\r\n            this.limitDate = null;\r\n            this.selectedMonths = [];\r\n            this.updateTotal();\r\n        },\r\n        //limit  es una fecha, con el mes y año actual, pero con el día del pago\r\n        //date es la fecha actual\r\n        //paymentday es solo el día\r\n        //\r\n        checkPenalty(date) {\r\n            let { total, penalty, days_extension } = this.currentPlan;\r\n\r\n            date = date.add(days_extension, \"days\");\r\n            if (this.date.isAfter(date.add())) {\r\n                if (penalty) {\r\n                    let { percentage, type } = penalty;\r\n                    percentage =\r\n                        type == \"percentage\"\r\n                            ? Number(percentage) / 100\r\n                            : Number(percentage);\r\n                    let totalPerDay =\r\n                        type == \"percentage\" ? total * percentage : percentage;\r\n                    let days = this.date.diff(date, \"days\");\r\n                    let month = date.get(\"month\") + 1;\r\n                    let nameMonth = this.months.find(m => m.id == month).label;\r\n                    this.penalties.push({\r\n                        id: month,\r\n                        days,\r\n                        label: nameMonth,\r\n                        penalty: days * totalPerDay\r\n                    });\r\n                }\r\n            }\r\n        },\r\n        selectMonth() {\r\n            this.penalties = [];\r\n            if (this.paymentDay) {\r\n                this.selectedMonths.forEach(sm => {\r\n                    let date = moment(\r\n                        `${sm}-${this.paymentDay}-${this.date.format(\"Y\")}`\r\n                    );\r\n                    this.checkPenalty(date);\r\n                });\r\n            }\r\n            this.updateTotal();\r\n        },\r\n        initForm() {\r\n            this.currentPlan = null;\r\n            this.penalties = [];\r\n            this.paymentDay = null;\r\n            this.form = {};\r\n            this.months = [\r\n                { id: 1, label: \"Enero\", disabled: false },\r\n                { id: 2, label: \"Febrero\", disabled: false },\r\n                { id: 3, label: \"Marzo\", disabled: false },\r\n                { id: 4, label: \"Abril\", disabled: false },\r\n                { id: 5, label: \"Mayo\", disabled: false },\r\n                { id: 6, label: \"Junio\", disabled: false },\r\n                { id: 7, label: \"Julio\", disabled: false },\r\n                { id: 8, label: \"Agosto\", disabled: false },\r\n                { id: 9, label: \"Setiembre\", disabled: false },\r\n                { id: 10, label: \"Octubre\", disabled: false },\r\n                { id: 11, label: \"Noviembre\", disabled: false },\r\n                { id: 12, label: \"Diciembre\", disabled: false }\r\n            ];\r\n        },\r\n        typeParent(type) {\r\n            let types = {\r\n                mother: \"Madre:\",\r\n                father: \"Padre:\",\r\n                attorney: \"Apoderado:\"\r\n            };\r\n\r\n            return types[type];\r\n        },\r\n\r\n        async setMonths() {\r\n            this.months = [\r\n                { id: 1, label: \"Enero\", disabled: false },\r\n                { id: 2, label: \"Febrero\", disabled: false },\r\n                { id: 3, label: \"Marzo\", disabled: false },\r\n                { id: 4, label: \"Abril\", disabled: false },\r\n                { id: 5, label: \"Mayo\", disabled: false },\r\n                { id: 6, label: \"Junio\", disabled: false },\r\n                { id: 7, label: \"Julio\", disabled: false },\r\n                { id: 8, label: \"Agosto\", disabled: false },\r\n                { id: 9, label: \"Setiembre\", disabled: false },\r\n                { id: 10, label: \"Octubre\", disabled: false },\r\n                { id: 11, label: \"Noviembre\", disabled: false },\r\n                { id: 12, label: \"Diciembre\", disabled: false }\r\n            ];\r\n            if (this.form.plan_id) {\r\n                let months = this.monthsPayed.filter(\r\n                    m => m.plan_id == this.form.plan_id\r\n                );\r\n\r\n                months.forEach(m => {\r\n                    this.months.find(n => n.id == m.month).disabled = true;\r\n                });\r\n            }\r\n        },\r\n\r\n        async updateTotal() {\r\n            if (!this.form.plan_id) {\r\n                return;\r\n            }\r\n            this.setMonths();\r\n            let plan = this.plans.find(p => p.id == this.form.plan_id);\r\n\r\n            let items = [];\r\n            if (plan) {\r\n                this.currentPlan = plan;\r\n                if (plan.payment_date) {\r\n                    this.paymentDay = plan.payment_date.split(\"/\")[0];\r\n                    this.limitDate = moment().set(\"date\", this.paymentDay);\r\n                }\r\n                items = plan.services.map(s => {\r\n                    s.item.sale_unit_price =\r\n                        s.price * this.selectedMonths.length;\r\n                    s.item.percentage_igv = 18;\r\n\r\n                    return s.item;\r\n                });\r\n            } else {\r\n                this.currentPlan = null;\r\n                this.paymentDay = null;\r\n                this.limitDate = null;\r\n            }\r\n\r\n            let { name, description } = plan;\r\n            let { id, parent, person } = this.member;\r\n\r\n            let observation = `${name} - ${description